16: func ProvideService(db db.DB, cfg *setting.Cfg, quotaService quota.Service) (apikey.Service, error) {
17: 	s := &Service{
18: 		store: &sqlStore{db: db},
19: 	}
20: 	defaultLimits, err := readQuotaConfig(cfg)
21: 	if err != nil {
22: 		return s, err
23: 	}
24: 
25: 	if err := quotaService.RegisterQuotaReporter(&quota.NewUsageReporter{
26: 		TargetSrv:     apikey.QuotaTargetSrv,
27: 		DefaultLimits: defaultLimits,
28: 		Reporter:      s.Usage,
29: 	}); err != nil {
30: 		return s, err
31: 	}
32: 
33: 	return s, nil
34: }
