44: 	return s.store.GetApiKeyByName(ctx, query)
45: }
46: func (s *Service) GetAPIKeyByHash(ctx context.Context, hash string) (*apikey.APIKey, error) {
47: 	return s.store.GetAPIKeyByHash(ctx, hash)
48: }
49: func (s *Service) AddAPIKey(ctx context.Context, cmd *apikey.AddCommand) (res *apikey.APIKey, err error) {
50: 	return s.store.AddAPIKey(ctx, cmd)
51: }
52: func (s *Service) UpdateAPIKeyLastUsedDate(ctx context.Context, tokenID int64) error {
53: 	return s.store.UpdateAPIKeyLastUsedDate(ctx, tokenID)
54: }
55: 
56: func readQuotaConfig(cfg *setting.Cfg) (*quota.Map, error) {
57: 	limits := &quota.Map{}
58: 
59: 	if cfg == nil {
60: 		return limits, nil
61: 	}
62: 
63: 	globalQuotaTag, err := quota.NewTag(apikey.QuotaTargetSrv, apikey.QuotaTarget, quota.GlobalScope)
64: 	if err != nil {
65: 		return limits, err
66: 	}
67: 	orgQuotaTag, err := quota.NewTag(apikey.QuotaTargetSrv, apikey.QuotaTarget, quota.OrgScope)
68: 	if err != nil {
69: 		return limits, err
70: 	}
71: 
72: 	limits.Set(globalQuotaTag, cfg.Quota.Global.ApiKey)
73: 	limits.Set(orgQuotaTag, cfg.Quota.Org.ApiKey)
74: 	return limits, nil
75: }
