103: func (ss *sqlStore) UpdateAPIKeyLastUsedDate(ctx context.Context, tokenID int64) error {
104: 	now := timeNow()
105: 	return ss.db.WithDbSession(ctx, func(sess *db.Session) error {
106: 		if _, err := sess.Table("api_key").ID(tokenID).Cols("last_used_at").Update(&apikey.APIKey{LastUsedAt: &now}); err != nil {
107: 			return err
108: 		}
109: 
110: 		return nil
111: 	})
112: }
